// This code cleans up LinkedIn URLs to find duplicates
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let normalizedUrl = null;

  if (data.linkedin_url) {
    // Convert to lowercase
    let url = data.linkedin_url.toLowerCase().trim();

    // Remove http/https and www
    url = url.replace(/^https?:\/\/(www\.)?/, '');

    // Remove trailing slashes
    url = url.replace(/\/$/, '');

    // Extract just the profile path (linkedin.com/in/username)
    const match = url.match(/linkedin\.com\/in\/([a-z0-9-]+)/);

    if (match) {
      normalizedUrl = `linkedin.com/in/${match[1]}`;
    }
  }

  results.push({
    json: {
      ...data,
      normalized_linkedin_url: normalizedUrl
    }
  });
}

return results;

const items = $input.all();
const unique = [];
const duplicates = [];

for (const item of items) {
  const data = item.json;

  if (data.duplicate_count === 1) {
    // Only one record with this URL - it's unique
    unique.push({
      json: {
        normalized_linkedin_url: data.normalized_linkedin_url,
        record_id: data.record_ids[0]
      }
    });
  } else if (data.duplicate_count > 1) {
    // Multiple records - these are duplicates
    duplicates.push({
      json: {
        normalized_linkedin_url: data.normalized_linkedin_url,
        record_ids: data.record_ids,
        duplicate_count: data.duplicate_count
      }
    });
  }
}

// Return as array of arrays for multiple outputs
return { 0: unique, 1: duplicates };

const items = $input.all();
const mergedRecords = [];
const recordsToMerge = [];

// Group items by normalized_linkedin_url
const groups = {};
for (const item of items) {
  const url = item.json.normalized_linkedin_url;
  if (!groups[url]) {
    groups[url] = [];
  }
  groups[url].push(item.json);
}

// Process each duplicate group
for (const [url, records] of Object.entries(groups)) {
  if (records.length === 1) continue; // Skip if somehow only one record

  // Sort by created_at to pick oldest as primary
  records.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

  const primaryRecord = records[0];
  const duplicateRecords = records.slice(1);

  // Merge: take first non-null value for each field
  const merged = {
    record_id: primaryRecord.record_id,
    normalized_linkedin_url: url,
    first_name: null,
    last_name: null,
    email: null,
    phone: null,
    linkedin_url: primaryRecord.linkedin_url
  };

  // Collect best values from all records
  for (const record of records) {
    if (!merged.first_name && record.first_name) merged.first_name = record.first_name;
    if (!merged.last_name && record.last_name) merged.last_name = record.last_name;
    if (!merged.email && record.email) merged.email = record.email;
    if (!merged.phone && record.phone) merged.phone = record.phone;
  }

  mergedRecords.push({
    json: {
      ...merged,
      status: 'crm_ready',
      is_primary: true
    }
  });

  // Mark duplicates for update
  for (const dup of duplicateRecords) {
    recordsToMerge.push({
      json: {
        record_id: dup.record_id,
        merged_into: primaryRecord.record_id,
        status: 'merged'
      }
    });
  }
}

// Return both arrays: merged primary records and duplicate markers

return {0:mergedRecords,1: recordsToMerge};
